// รับค่า Markdown จาก Node HTTP Request
// (ถ้า Jina คืนค่ามาเป็น text ตรงๆ ให้ใช้ $input.first().json.data)
let markdownContent = $input.first().json.data || $input.first().json; 

// หั่นข้อความด้วยคำว่า "ติดต่อ\n"
let blocks = markdownContent.split("ติดต่อ\n");
let result = [];

// วนลูปเพื่อจัดรูปแบบ (เริ่มจาก index 1 เพราะ index 0 คือส่วน Header ของเว็บ)
for (let i = 1; i < blocks.length; i++) {
  let blockText = blocks[i].trim();

  // กรองเอาเฉพาะบล็อคที่มีสัญลักษณ์ "฿" (เพื่อยืนยันว่าเป็นประกาศขาย/เช่าจริงๆ)
  if (blockText.includes("฿")) {

    // สร้าง ID จำลองขึ้นมาเพื่อใช้เช็คซ้ำใน Node Compare Datasets
    let listing_id = "JINA" + (Math.floor(Math.random() * 900000) + 100000);

    result.push({
      json: {
        listing_id: listing_id,
        raw_text: blockText, // ส่งก้อนข้อความนี้ให้ AI Agent ดึงข้อมูลต่อ
        fetched_at: new Date().toISOString()
      }
    });
  }
}

// จำกัดจำนวนส่งให้ AI (เช่น 5 รายการ) เพื่อประหยัดเวลาและ Token
return result.slice(0, 5);

